import { getCalApiConfig } from "./env";
import type { ApiResponse } from "./types";

type Method = "GET" | "POST" | "PATCH" | "DELETE";

type RequestOptions = {
  method?: Method;
  query?: Record<string, string | number | boolean | undefined>;
  body?: unknown;
  apiVersion?: string;
  cache?: RequestCache;
  next?: { revalidate?: number; tags?: string[] };
  retries?: number;
};

class CalApiError extends Error {
  code: string;
  status: number;
  details?: unknown;

  constructor(
    message: string,
    code: string,
    status: number,
    details?: unknown,
  ) {
    super(message);
    this.name = "CalApiError";
    this.code = code;
    this.status = status;
    this.details = details;
  }
}

function buildQuery(query?: RequestOptions["query"]): string {
  if (!query) {
    return "";
  }

  const params = new URLSearchParams();

  for (const [key, value] of Object.entries(query)) {
    if (value === undefined || value === null) {
      continue;
    }
    params.set(key, String(value));
  }

  const str = params.toString();
  return str ? `?${str}` : "";
}

function sleep(ms: number): Promise<void> {
  return new Promise<void>((resolve) => setTimeout(resolve, ms));
}

export async function calApi<T>(
  path: string,
  options: RequestOptions = {},
): Promise<T> {
  const { apiKey, apiUrl, apiVersion } = getCalApiConfig();
  const url = `${apiUrl}${path}${buildQuery(options.query)}`;
  const method = options.method ?? "GET";
  const isIdempotent = method === "GET";
  const maxRetries = options.retries ?? (isIdempotent ? 2 : 0);

  const headers: Record<string, string> = {
    Accept: "application/json",
    Authorization: `Bearer ${apiKey}`,
    "cal-api-version": options.apiVersion ?? apiVersion,
  };

  if (options.body !== undefined) {
    headers["Content-Type"] = "application/json";
  }

  let lastError: CalApiError | null = null;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const response = await fetch(url, {
      body:
        options.body === undefined ? undefined : JSON.stringify(options.body),
      cache: options.cache,
      headers,
      method,
      next: options.next,
    });

    let payload: ApiResponse<T> | undefined;

    try {
      payload = (await response.json()) as ApiResponse<T>;
    } catch {
      if (!response.ok) {
        lastError = new CalApiError(
          `Cal.com API ${response.status} ${response.statusText}`,
          "UNKNOWN",
          response.status,
        );
      } else {
        throw new CalApiError(
          "Cal.com API returned no body",
          "EMPTY_BODY",
          500,
        );
      }
    }

    if (payload && response.ok && payload.status === "success") {
      return payload.data;
    }

    if (!lastError) {
      const err = payload?.status === "error" ? payload.error : undefined;
      lastError = new CalApiError(
        err?.message ?? `Cal.com API ${response.status}`,
        err?.code ?? `HTTP_${response.status}`,
        response.status,
        err?.details,
      );
    }

    const shouldRetry =
      attempt < maxRetries &&
      (lastError.status === 429 || lastError.status === 503);

    if (!shouldRetry) {
      break;
    }

    const retryAfter = Number(response.headers.get("retry-after"));
    const backoffMs =
      Number.isFinite(retryAfter) && retryAfter > 0
        ? Math.min(retryAfter * 1000, 5000)
        : 400 * 2 ** attempt + Math.floor(Math.random() * 200);

    await sleep(backoffMs);
    lastError = null;
  }

  throw (
    lastError ?? new CalApiError("Cal.com API request failed", "UNKNOWN", 500)
  );
}

export { CalApiError };

function required(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(
      `Missing env var: ${name}. Copy .env.example to .env.local and fill it in.`,
    );
  }
  return value;
}

export function getCalApiConfig(): {
  apiKey: string;
  apiUrl: string;
  apiVersion: string;
} {
  return {
    apiKey: required("CAL_API_KEY"),
    apiUrl: process.env.CAL_API_URL ?? "https://api.cal.com/v2",
    apiVersion: process.env.CAL_API_VERSION ?? "2024-08-13",
  };
}

import "server-only";

import { calApi } from "./client";
import type { EventType } from "./types";

const EVENT_TYPES_API_VERSION = "2024-06-14";

export async function listEventTypes(params: {
  username?: string;
  teamId?: number;
  teamSlug?: string;
  orgId?: number;
  orgSlug?: string;
  isTeamEvent?: boolean;
  eventSlug?: string;
}): Promise<EventType[]> {
  const cacheKey =
    params.teamId?.toString() ?? params.teamSlug ?? params.username ?? "all";

  return calApi<EventType[]>("/event-types", {
    apiVersion: EVENT_TYPES_API_VERSION,
    next: { revalidate: 60, tags: ["event-types", cacheKey] },
    query: {
      eventSlug: params.eventSlug,
      isTeamEvent: params.isTeamEvent,
      orgId: params.orgId,
      orgSlug: params.orgSlug,
      teamId: params.teamId,
      teamSlug: params.teamSlug,
      username: params.username,
    },
  });
}

export async function getEventType(params: {
  username: string;
  eventSlug: string;
  orgId?: number;
  orgSlug?: string;
}): Promise<EventType | null> {
  const matches = await listEventTypes(params);
  return matches[0] ?? null;
}

export async function getTeamEventType(params: {
  teamId: number;
  eventSlug: string;
  orgId?: number;
}): Promise<EventType | null> {
  const matches = await listEventTypes({
    eventSlug: params.eventSlug,
    isTeamEvent: true,
    orgId: params.orgId,
    teamId: params.teamId,
  });
  return matches[0] ?? null;
}

export async function getTeamSlugEventType(params: {
  teamSlug: string;
  eventSlug: string;
  orgId?: number;
  orgSlug?: string;
}): Promise<EventType | null> {
  const matches = await listEventTypes({
    eventSlug: params.eventSlug,
    isTeamEvent: true,
    orgId: params.orgId,
    orgSlug: params.orgSlug,
    teamSlug: params.teamSlug,
  });
  return matches[0] ?? null;
}

export async function getEventTypeById(
  eventTypeId: number,
): Promise<EventType> {
  return calApi<EventType>(`/event-types/${eventTypeId}`, {
    apiVersion: EVENT_TYPES_API_VERSION,
    next: { revalidate: 60, tags: [`event-type-${eventTypeId}`] },
  });
}

import "server-only";

import { calApi } from "./client";

const SLOTS_API_VERSION = "2024-09-04";

export async function getAvailableSlots(params: {
  start: string;
  end: string;
  timeZone: string;
  username?: string;
  eventTypeSlug?: string;
  eventTypeId?: number;
}): Promise<unknown> {
  return calApi<unknown>("/slots", {
    apiVersion: SLOTS_API_VERSION,
    next: {
      revalidate: 60,
      tags: [
        "slots",
        params.eventTypeId?.toString() ??
          `${params.username}-${params.eventTypeSlug}`,
        params.start,
      ],
    },
    query: {
      end: params.end,
      eventTypeId: params.eventTypeId,
      eventTypeSlug: params.eventTypeSlug,
      start: params.start,
      timeZone: params.timeZone,
      username: params.username,
    },
  });
}

export type ApiSuccess<T> = {
  status: "success";
  data: T;
};

export type ApiError = {
  status: "error";
  timestamp?: string;
  path?: string;
  error: {
    code: string;
    message: string;
    details?: unknown;
  };
};

export type ApiResponse<T> = ApiSuccess<T> | ApiError;

export type EventTypeLocation = {
  type: string;
  address?: string;
  link?: string;
  hostPhoneNumber?: string;
  displayLocationPublicly?: boolean;
};

export type EventTypeOwner = {
  id: number;
  username: string;
  name?: string | null;
  avatarUrl?: string | null;
  weekStart?: string;
  timeZone?: string;
  brandColor?: string | null;
  darkBrandColor?: string | null;
};

export type EventTypeTeam = {
  id: number;
  slug: string;
  name: string;
  bannerUrl?: string | null;
  logoUrl?: string | null;
};

export type EventType = {
  id: number;
  slug: string;
  title: string;
  description?: string | null;
  lengthInMinutes: number;
  locations: EventTypeLocation[];
  bookingFields?: BookingField[];
  disableGuests?: boolean;
  hidden?: boolean;
  requiresConfirmation?: boolean;
  isInstantEvent?: boolean;
  ownerId?: number;
  teamId?: number;
  team?: EventTypeTeam;
  users?: EventTypeOwner[];
  hosts?: EventTypeOwner[];
  metadata?: Record<string, unknown>;
};

export type BookingFieldType =
  | "name"
  | "email"
  | "phone"
  | "text"
  | "textarea"
  | "number"
  | "select"
  | "multiselect"
  | "checkbox"
  | "radio"
  | "boolean"
  | "url"
  | "address";

export type BookingField = {
  slug: string;
  type: BookingFieldType;
  label?: string;
  placeholder?: string;
  required?: boolean;
  disableOnPrefill?: boolean;
  hidden?: boolean;
  options?: Array<{ label: string; value: string }>;
};

export type Slot = {
  start: string;
  attendees?: number;
  bookingUid?: string;
};

export type AvailableSlots = Record<string, Slot[]>;

export type BookingAttendee = {
  name: string;
  email: string;
  timeZone: string;
  language?: string;
  phoneNumber?: string;
};

export type Booking = {
  uid: string;
  id: number;
  title: string;
  status: "accepted" | "pending" | "cancelled" | "rejected" | "awaiting_host";
  start: string;
  end: string;
  duration: number;
  eventTypeId: number;
  eventType?: { id: number; slug: string; title?: string };
  attendees: BookingAttendee[];
  hosts: Array<{ id: number; name: string; email: string; username?: string }>;
  meetingUrl?: string | null;
  location?: string;
  absentHost?: boolean;
  createdAt?: string;
  updatedAt?: string;
  metadata?: Record<string, unknown>;
  rescheduledFromUid?: string;
};

export type CreateBookingInput = {
  start: string;
  eventTypeId: number;
  attendee: BookingAttendee;
  guests?: string[];
  bookingFieldsResponses?: Record<string, unknown>;
  location?: string;
  metadata?: Record<string, unknown>;
  lengthInMinutes?: number;
